} from '@mikro-orm/decorators/legacy';

@Embeddable()
class Address {
  @Property()
  city!: string;
}

@Embeddable()
class Company {
  @Property()
  name!: string;

  @Embedded(() => Address, { prefix: 'addr_', prefixMode: 'relative' })
  address!: Address;

  @Embedded(() => Address, { prefix: 'addr2_' /* mode from configuration */ })
  address2!: Address;
}

@Entity()
class Person {
  @PrimaryKey()
  id!: number;

  @Embedded(() => Address)
  address!: Address;

  @Embedded(() => Company, { prefix: 'comp_' })
  company!: Company;
}

