import assert from 'node:assert/strict';
import { EntitySchema, MikroORM } from '@mikro-orm/sqlite';

class Nested {
  value?: string | null;
}

const NestedSchema = new EntitySchema<Nested>({
  class: Nested,
  embeddable: true,
  properties: {
    value: { type: 'string', nullable: true },
  },
});

class Parent {
  nested?: Nested | null;
}

const ParentSchema = new EntitySchema<Parent>({
  class: Parent,
  embeddable: true,
  properties: {
    nested: { kind: 'embedded', entity: () => Nested, nullable: true },
  },
});

class Root {
  id!: number;
  parent: Parent | null = null;
}

const RootSchema = new EntitySchema<Root>({
  class: Root,
  properties: {
    id: { type: 'number', primary: true },
    parent: { kind: 'embedded', entity: () => Parent, nullable: true },
  },
});

async function main() {
  const orm = await MikroORM.init({
    entities: [RootSchema, ParentSchema, NestedSchema],
    dbName: ':memory:',
    allowGlobalContext: true,
  } as any);
  await orm.schema.create();

  const snapshot = orm.em.getComparator().getSnapshotGenerator(Root);

  const parentNull = orm.em.create(Root, { parent: null });
  assert.deepEqual(snapshot(parentNull), { parent_nested_value: null });

  const nestedNull = orm.em.create(Root, { parent: { nested: null } });
  assert.deepEqual(snapshot(nestedNull), { parent_nested_value: null });

  const nestedValue = orm.em.create(Root, { parent: { nested: { value: 'ok' } } });
  assert.deepEqual(snapshot(nestedValue), { parent_nested_value: 'ok' });

  await orm.em.persist([parentNull, nestedNull, nestedValue]).flush();
  const rows = await orm.em.getConnection().execute('select * from root order by id');
  assert.deepEqual(rows, [
    { id: 1, parent_nested_value: null },
    { id: 2, parent_nested_value: null },
    { id: 3, parent_nested_value: 'ok' },
  ]);

  await orm.close(true);
}

main().catch(e => { console.error(e); process.exit(1); });
